def nullify_str(col):
    s = F.trim(col.cast("string"))
    return (
        F.when(col.isNull(), None)
         .when(F.lower(s).isin("undefined", "null", "none", ""), None)
         .otherwise(s)
    )

def make_uuid_from_text(text: str) -> str:
    if text is None:
        return None
    return str(uuid.uuid5(uuid.NAMESPACE_DNS, text))

uuid_udf = F.udf(make_uuid_from_text)
